                var cumDev=0;var cumMin=Infinity;var cumMax=-Infinity;var ssq=0;
                for(var wk2=wStart;wk2<wStart+wSz;wk2++){cumDev+=rets[wk2]-wMean;if(cumDev<cumMin)cumMin=cumDev;if(cumDev>cumMax)cumMax=cumDev;ssq+=(rets[wk2]-wMean)*(rets[wk2]-wMean);}
