          if(hRunLen[h]>0&&hRunStartPrice[h]!==null&&hRunStartPrice[h]>0){var excLast=Math.abs(hClose[h]-hRunStartPrice[h])/hRunStartPrice[h]*100;if(hRunExcursions[h].length<5000)hRunExcursions[h].push(excLast);if(hRunDir[h]===1&&hUpExcursions[h].length<5000)hUpExcursions[h].push(excLast);else if(hRunDir[h]===-1&&hDownExcursions[h].length<5000)hDownExcursions[h].push(excLast);}
