  var lS={color:C.txtDim,fontSize:8,fontWeight:600,letterSpacing:1,textTransform:'uppercase',fontFamily:F,marginBottom:4,display:'block'};
  var iS={width:'100%',background:C.bgInput,border:'1px solid '+C.border,borderRadius:6,color:C.txtBright,fontFamily:F,fontSize:12,fontWeight:600,padding:'10px 12px',outline:'none'};
  var bB={width:'100%',padding:'12px',border:'none',borderRadius:8,fontFamily:F,fontSize:11,fontWeight:700,letterSpacing:1.5,textTransform:'uppercase',cursor:'pointer'};

  var featureLabels={hour_atr_dollar:'Hourly ATR ($)',hour_atr_pct:'Hourly ATR (%)',hour_volume:'Hourly Volume',hour_trades:'Hourly Trades',price_vs_day_open_pct:'Price vs Day Open (%)',intraday_range_pct:'Intraday Range (%)',cumulative_volume_pct:'Cumulative Volume (%)',overnight_gap_pct:'Overnight Gap (%)',vix_close:'VIX Proxy (UVXY)',day_of_week:'Day of Week',hour:'Hour of Day',day_volume:'Day Volume',day_trades:'Day Trades',hour_open:'Hour Open',hour_close:'Hour Close',hour_high:'Hour High',hour_low:'Hour Low',hour_vwap:'Hour VWAP',day_open:'Day Open',day_close:'Day Close',day_high:'Day High',day_low:'Day Low',prev_day_close:'Prev Day Close',hour_range_dollar:'Hour Range ($)',hour_close_vs_open_pct:'Hour Direction (%)',hour_vol_pct_of_day:'Hour Vol % of Day',prev_hour_atr_pct:'Prev Hour ATR (%)',prev_hour_atr_dollar:'Prev Hour ATR ($)',prev_hour_volume:'Prev Hour Volume',prev_hour_trades:'Prev Hour Trades',prev_hour_direction:'Prev Hour Direction (%)',prev_hour_range_dollar:'Prev Hour Range ($)',prev_hour_best_tp:'Prev Hour Best TP%',price_vs_prev_close_pct:'Price vs Prev Close (%)',is_rth:'Is RTH (9:30-4)',day_range_pct_hl:'Day Range % (H-L)',hour_seasonal_atr:'Hour Seasonal ATR (%)',hour_seasonal_volume:'Hour Seasonal Volume',hour_seasonal_realized_vol:'Hour Seasonal Realized Vol',hour_seasonal_best_tp:'Hour Seasonal Best TP%',atr_vs_hour_seasonal:'ATR vs Hour Seasonal',volume_vs_hour_seasonal:'Volume vs Hour Seasonal',realized_vol_vs_hour_seasonal:'Realized Vol vs Hour Seasonal',reversals_vs_hour_seasonal:'Reversals vs Hour Seasonal',dow_seasonal_atr:'DOW Seasonal ATR (%)',dow_seasonal_volume:'DOW Seasonal Volume',dow_seasonal_best_tp:'DOW Seasonal Best TP%',atr_vs_dow_seasonal:'ATR vs DOW Seasonal',volume_vs_dow_seasonal:'Volume vs DOW Seasonal',atr_acceleration:'ATR Acceleration (%)',realized_vol_acceleration:'Realized Vol Accel (%)',tick_vol_acceleration:'Tick Vol Accel (%)',reversal_rate_acceleration:'Reversal Rate Accel (%)',volume_acceleration:'Volume Acceleration (%)',atr_ratio_3h:'ATR Ratio vs 3h Avg',realized_vol_ratio_3h:'Realized Vol Ratio vs 3h',vol_compression_3h:'Vol Compression 3h',vol_expansion_streak:'Vol Expansion Streak',range_percentile_8h:'Range Percentile 8h',drawdown_trend_3h:'Drawdown Trend 3h',price_momentum_3h:'Price Momentum 3h (%)',hour_realized_vol:'Hour Realized Vol (%)',hour_tick_volatility:'Hour Tick Volatility (c)',hour_return_pct:'Hour Return (%)',hour_max_drawdown_pct:'Hour Max Drawdown (%)',hour_range_vs_prev:'Hour Range vs Prev',hour_upper_wick_pct:'Hour Upper Wick (%)',first_15min_range_pct:'First 15min Range (%)',hour_avg_trade_size:'Hour Avg Trade Size',hour_trade_intensity:'Hour Trades/Min',hour_up_down_ratio:'Hour Up/Down Ratio',hour_reversal_count:'Hour Reversal Count',hour_reversal_rate:'Hour Reversal Rate',prev_hour_realized_vol:'Prev Hour Realized Vol (%)',prev_hour_tick_volatility:'Prev Hour Tick Vol (c)',prev_hour_return_pct:'Prev Hour Return (%)',prev_hour_max_drawdown_pct:'Prev Hour Max DD (%)',prev_hour_reversal_rate:'Prev Hour Reversal Rate',prev_hour_avg_trade_size:'Prev Hour Avg Trade Size',prev_hour_trade_intensity:'Prev Hour Trades/Min',hour_return_autocorr:'Hour Return Autocorr',hour_hurst_exponent:'Hour Hurst Exponent',hour_mean_reversion_hl:'Hour MR Half-Life (ticks)',hour_avg_run_length:'Hour Avg Run Length',hour_avg_up_run:'Hour Avg Up Run',hour_avg_down_run:'Hour Avg Down Run',hour_run_asymmetry:'Hour Run Asymmetry',hour_oscillation_score:'Hour Oscillation Score',prev_hour_autocorr:'Prev Hour Autocorr',prev_hour_hurst:'Prev Hour Hurst',prev_hour_half_life:'Prev Hour Half-Life',prev_hour_avg_run:'Prev Hour Avg Run',prev_hour_oscillation_score:'Prev Hour Oscillation Score',atr_avg_2h:'ATR Avg 2h',atr_ratio_2h:'ATR Ratio vs 2h',atr_avg_4h:'ATR Avg 4h',atr_ratio_4h:'ATR Ratio vs 4h',atr_std_4h:'ATR Std Dev 4h',atr_min_4h:'ATR Min 4h',atr_max_4h:'ATR Max 4h',atr_avg_8h:'ATR Avg 8h',atr_ratio_8h:'ATR Ratio vs 8h',intensity_avg_3h:'Intensity Avg 3h',intensity_ratio_3h:'Intensity Ratio vs 3h',volume_avg_3h:'Volume Avg 3h',volume_ratio_3h:'Volume Ratio vs 3h',trade_size_acceleration:'Trade Size Accel (%)',trade_size_ratio_3h:'Trade Size Ratio vs 3h',atr_acceleration_2h:'ATR Accel 2h Skip (%)',realized_vol_delta_abs:'Realized Vol Delta (abs)',atr_delta_abs:'ATR Delta (abs)',regime_intensity_score:'Regime Intensity Score'};
  var featureDescriptions={hour_atr_pct:'Percentage range of the hour. Higher ATR% = more price movement = more oscillation opportunities.',hour_atr_dollar:'Dollar range within the hour. Wider range may favor wider TP% to capture larger swings.',hour_volume:'Share volume traded in this hour. High volume = more liquidity, more ticks, more cycle opportunities.',hour_trades:'Number of individual trade executions. More trades = finer price granularity for the cycle engine.',price_vs_day_open_pct:'How far price has moved from day open. Trending days show persistent direction; mean-reversion days oscillate around open. Known at start of each hour.',intraday_range_pct:'Total day range as % of low so far. Measures overall volatility. Known at start of each hour.',cumulative_volume_pct:'What fraction of the day volume has traded by this hour. Known at start of each hour.',overnight_gap_pct:'Gap between prev close and today open. Large gaps often lead to mean-reversion or continuation. Known before 4AM.',vix_close:'UVXY (VIX proxy ETF) price at this hour. Tracks VIX futures, captures intraday fear spikes. Pre-market hours forward-filled from nearest available value. Known from previous hour.',day_of_week:'Monday=1 through Friday=5. Some days have consistently different volatility profiles. Known before market.',hour:'Hour of day (4-19 ET). Different hours have different liquidity and volatility patterns. Known before the hour.',hour_range_dollar:'Dollar range within the hour (high - low). Direct measure of price movement magnitude.',hour_close_vs_open_pct:'Hour close vs open as %. Positive = price rose during the hour. Measures directional movement.',hour_vol_pct_of_day:'This hour volume as % of total day volume. Measures relative activity concentration.',prev_hour_atr_pct:'Previous hour ATR%. The most recent volatility signal before the current hour. Key leadable predictor.',prev_hour_atr_dollar:'Previous hour ATR in dollars. Absolute volatility of the just-completed hour.',prev_hour_volume:'Previous hour volume. Recent liquidity level before current hour.',prev_hour_trades:'Previous hour trade count. Recent market activity granularity.',prev_hour_direction:'Previous hour close vs open %. Was the last hour bullish or bearish? May affect next hour TP%.',prev_hour_range_dollar:'Previous hour dollar range (high - low). How wide did price swing last hour.',prev_hour_best_tp:'What was the optimal TP% last hour? Strong persistence = current hour may favor similar setting.',price_vs_prev_close_pct:'Current price vs previous day close %. Shows how far the stock has moved from yesterday. Known at start of hour.',is_rth:'1 if regular trading hours (9:30-4PM), 0 if pre/post market. RTH has different volatility and liquidity. Known before the hour.',day_range_pct_hl:'Day range computed from day high minus day low as % of low. Broader measure than intraday_range_pct.',hour_seasonal_atr:'Average ATR% for this hour of day across all days in the dataset. The baseline volatility level for this time slot.',hour_seasonal_volume:'Average volume for this hour across all days. Baseline liquidity for this time slot.',hour_seasonal_realized_vol:'Average realized vol for this hour across all days. Baseline oscillation intensity.',hour_seasonal_best_tp:'Average optimal TP% for this hour across all days. Shows the typical best TP% for this time slot.',atr_vs_hour_seasonal:'This hour ATR divided by the seasonal average for this hour. Greater than 1 = above-normal volatility. Key signal: abnormal volatility may require different TP%.',volume_vs_hour_seasonal:'This hour volume divided by seasonal average. Greater than 1 = above-normal activity. Unusual volume often predicts regime change.',realized_vol_vs_hour_seasonal:'Realized vol ratio vs seasonal norm. Measures oscillation intensity relative to what is typical for this hour.',reversals_vs_hour_seasonal:'Reversal rate vs seasonal norm. Above-normal reversals = more mean-reversion than usual.',dow_seasonal_atr:'Average ATR% for this day of week across all data. Baseline weekday volatility.',dow_seasonal_volume:'Average volume for this day of week. Baseline weekday liquidity.',dow_seasonal_best_tp:'Average optimal TP% for this day of week. Shows if certain days consistently favor different TP%.',atr_vs_dow_seasonal:'ATR ratio vs day-of-week average. Measures if today is more or less volatile than typical for this weekday.',volume_vs_dow_seasonal:'Volume ratio vs day-of-week average. Above-normal volume for the weekday.',atr_acceleration:'Rate of change of ATR% vs previous hour. Positive = volatility accelerating, negative = decelerating. Captures regime transitions as they happen.',realized_vol_acceleration:'Rate of change of realized vol vs previous hour. Sudden spikes signal regime shift.',tick_vol_acceleration:'Rate of change of tick-to-tick volatility. Rapid increase may predict need for wider TP%.',reversal_rate_acceleration:'Rate of change of reversal rate. Increasing = becoming choppier. Decreasing = becoming more directional.',volume_acceleration:'Rate of change of volume vs previous hour. Volume surges often precede volatility changes.',atr_ratio_3h:'Current hour ATR divided by average ATR of previous 3 hours. Greater than 1 = short-term volatility above medium-term baseline. Breakout signal.',realized_vol_ratio_3h:'Current realized vol vs 3-hour average. Identifies when oscillation intensity is spiking relative to recent history.',vol_compression_3h:'Minimum ATR divided by maximum ATR over last 3 hours. Low values (near 0) = squeezed, coiled volatility ready to expand. High values (near 1) = stable.',vol_expansion_streak:'Number of consecutive hours where ATR increased vs prior hour. Streak of 3+ = sustained volatility expansion regime.',range_percentile_8h:'Where current hour range sits relative to last 8 hours (0-100%). 90th percentile = this is one of the widest range hours today.',drawdown_trend_3h:'Average max drawdown over last 3 hours. Rising trend = increasing intra-hour risk. May signal need for wider TP% to avoid premature exits.',price_momentum_3h:'Cumulative return over last 3 hours. Large positive/negative = sustained trend. Near zero = oscillating (good for oscillation trading).',hour_realized_vol:'Standard deviation of tick-to-tick returns within the hour, expressed as %. THE core oscillation measure. Higher realized vol = more price movement for the cycle engine to capture.',hour_tick_volatility:'Average absolute tick-to-tick price change in cents. Pure choppiness signal independent of direction. High tick vol = lots of small oscillations ideal for tight TP%.',hour_return_pct:'Directional return for the hour (close vs open). Near zero = range-bound (good for oscillation trading). Large positive/negative = trending (may favor wider TP%).',hour_max_drawdown_pct:'Worst intra-hour pullback from running high. Large drawdowns indicate sharp reversals that could trap positions.',hour_range_vs_prev:'This hour range divided by previous hour range. Greater than 1 = volatility expanding. Less than 1 = contracting. Regime change detector.',hour_upper_wick_pct:'Upper wick as percentage of total range. High upper wick = price rejected highs and pulled back. May indicate mean-reversion environment.',first_15min_range_pct:'Range of the first 15 minutes of the hour as % of price. Early range often sets the tone. Wide opening range may predict continued volatility.',hour_avg_trade_size:'Average shares per trade execution. Large avg size = institutional flow. Small avg size = retail/fractional dominated.',hour_trade_intensity:'Trade executions per minute. High intensity = active market with fine price granularity for the cycle engine.',hour_up_down_ratio:'Ratio of up ticks to down ticks. Near 1.0 = balanced (good for oscillation trading). Far from 1.0 = directional pressure.',hour_reversal_count:'Number of price direction changes within the hour. More reversals = more oscillation = more potential cycles.',hour_reversal_rate:'Reversals per 100 ticks. Normalized choppiness measure. High reversal rate directly predicts cycle completion opportunity.',prev_hour_realized_vol:'Previous hour realized volatility. Key leadable predictor: recent oscillation intensity before the current hour.',prev_hour_tick_volatility:'Previous hour avg tick-to-tick move. Leadable choppiness signal from the just-completed hour.',prev_hour_return_pct:'Previous hour directional return. Was last hour trending or flat? Affects current hour TP% selection.',prev_hour_max_drawdown_pct:'Previous hour worst drawdown. Recent risk level before current hour.',prev_hour_reversal_rate:'Previous hour reversal rate. Leadable mean-reversion intensity signal.',prev_hour_avg_trade_size:'Previous hour avg trade size. Recent institutional vs retail flow.',prev_hour_trade_intensity:'Previous hour trades per minute. Recent activity density.',hour_return_autocorr:'Lag-1 autocorrelation of tick returns (-1 to +1). Negative = mean-reverting (price tends to reverse after each move). Positive = trending (moves persist). THE most direct measure of whether the cycle engine can profit. Computed via Pearson correlation between consecutive returns.',hour_hurst_exponent:'Hurst exponent via R/S analysis (0 to 1). H < 0.5 = mean-reverting, H = 0.5 = random walk, H > 0.5 = trending. Computed by measuring the rescaled range across multiple window sizes (8 to 128 ticks) and fitting log-log slope.',hour_mean_reversion_hl:'Mean reversion half-life in ticks. How many ticks until a deviation from the mean decays by half. Lower = faster reversion = more cycle opportunities. Derived from autocorrelation via Ornstein-Uhlenbeck model: HL = -ln(2)/ln(|r1|).',hour_avg_run_length:'Average number of consecutive ticks moving in the same direction before reversing. Short runs (1-2) = very choppy, ideal for tight TP%. Long runs (5+) = trending, may need wider TP%.',hour_avg_up_run:'Average length of consecutive up-tick sequences. Combined with avg_down_run reveals directional asymmetry.',hour_avg_down_run:'Average length of consecutive down-tick sequences.',hour_run_asymmetry:'Ratio of avg up-run to avg down-run. Greater than 1 = up-moves persist longer (bullish microstructure). Less than 1 = down-moves persist longer.',hour_oscillation_score:'Composite score 0-1 combining: negative autocorrelation, low Hurst, high reversal rate, and short run length. Higher = more oscillatory/choppy = better for the cycle engine. THE prediction target proxy.',prev_hour_autocorr:'Previous hour autocorrelation. Key leadable predictor: was the last hour mean-reverting or trending?',prev_hour_hurst:'Previous hour Hurst exponent. Recent regime classification.',prev_hour_half_life:'Previous hour mean reversion half-life. Recent speed of mean reversion.',prev_hour_avg_run:'Previous hour avg run length. Recent directional persistence.',prev_hour_oscillation_score:'Previous hour oscillation score. Direct leadable composite of how good the last hour was for oscillation trading.',atr_avg_2h:'Rolling 2-hour average ATR%. Very short-term volatility baseline. Captures the most recent regime.',atr_ratio_2h:'Current ATR vs 2-hour average. Tight window for detecting immediate regime shifts.',atr_avg_4h:'Rolling 4-hour average ATR%. Medium-term baseline spanning half a trading session.',atr_ratio_4h:'Current ATR vs 4-hour average. Captures whether current volatility is above/below the session half.',atr_std_4h:'Standard deviation of ATR over last 4 hours. Volatility of volatility. High = uneven, spikey. Low = steady regime.',atr_min_4h:'Minimum ATR in last 4 hours. The floor volatility level. Current ATR vs this floor shows how far above the minimum.',atr_max_4h:'Maximum ATR in last 4 hours. The ceiling. Current ATR near ceiling = still in high regime. Near floor = calming.',atr_avg_8h:'Rolling 8-hour (half-day) average ATR%. Long-term intraday baseline.',atr_ratio_8h:'Current ATR vs half-day average. Greater than 1 = above the day so far. Key for late-day regime detection.',intensity_avg_3h:'Average trades per minute over last 3 hours. Medium-term activity baseline.',intensity_ratio_3h:'Current intensity vs 3h average. Spike = unusual activity level for this part of the day.',volume_avg_3h:'Average volume over last 3 hours. Rolling liquidity baseline.',volume_ratio_3h:'Current volume vs 3h average. Detects volume surges relative to recent activity.',trade_size_acceleration:'Rate of change in avg trade size vs previous hour. Jump in trade size = institutional entry.',trade_size_ratio_3h:'Current avg trade size vs 3h average. Sustained large trade sizes = institutional regime.',atr_acceleration_2h:'ATR change over 2-hour gap (skipping 1 hour). Second derivative of volatility. Positive = acceleration itself is accelerating.',realized_vol_delta_abs:'Absolute change in realized vol (not percentage). Shows magnitude of oscillation shift regardless of base level.',atr_delta_abs:'Absolute change in ATR% (not percentage). Direct measure of how many percentage points volatility changed.',regime_intensity_score:'Composite score (0-1) combining: acceleration magnitude, expansion streak, and decompression. Higher = stronger regime transition underway. Normalized so comparable across stocks.',hour_return_autocorr:'Lag-1 autocorrelation of tick returns. Negative = mean-reverting. Positive = trending. THE most direct predictor.',hour_hurst_exponent:'Hurst exponent via R/S analysis. H less than 0.5 = mean-reverting. H = 0.5 = random walk. H greater than 0.5 = trending.',hour_mean_reversion_hl:'Half-life in ticks from OU model. Lower = faster reversion = more cycles.',hour_avg_run_length:'Average consecutive same-direction ticks. Short = choppy, ideal for tight TP%.',hour_avg_up_run:'Average up-tick run length. Combined with down-run reveals directional asymmetry.',hour_avg_down_run:'Average down-tick run length.',hour_run_asymmetry:'Up-run / down-run ratio. Near 1 = symmetric oscillation.',hour_oscillation_score:'Composite 0-1: autocorr + Hurst + reversals + runs. Higher = better for oscillation trading.',prev_hour_autocorr:'Previous hour autocorrelation. Key leadable predictor.',prev_hour_hurst:'Previous hour Hurst exponent. Recent regime classification.',prev_hour_half_life:'Previous hour half-life. Recent speed of mean reversion.',prev_hour_avg_run:'Previous hour avg run length. Recent directional persistence.',prev_hour_oscillation_score:'Previous hour oscillation score. Leadable composite.',hour_volume_per_min:'Shares traded per minute. Volume intensity for the cycle engine.',cumvol_rate:'Cumulative volume % divided by hours elapsed. Volume pace indicator.',cumvol_delta:'Change in hourly volume share vs previous hour. Volume surges precede volatility.',prev_hour_volume_per_min:'Previous hour volume per minute. Leadable volume intensity.',hour_ece_pct:'Expected Completed Excursion: average price change (%) of each completed directional run. This IS the average swing size the cycle engine can capture. Directly maps to optimal TP%.',hour_cwe_pct:'Cycle-Weighted Excursion: RMS of run excursions. Emphasizes large swings more than the mean. Higher CWE vs ECE means fat-tailed excursions with occasional large swings.',hour_cep_median:'Conditional Excursion Percentile: median (50th percentile) run excursion in %. The typical swing size. Half of all swings are smaller, half larger.',hour_cep_p90:'90th percentile excursion. Only 10% of swings are larger. Shows the tail behavior: occasional large moves that could benefit from wider TP%.',hour_cep_tail_ratio:'P90/P50 ratio. Measures how fat-tailed the excursion distribution is. Ratio of 2 = the large swings are 2x the typical swing. High ratio = occasional outsized moves.',hour_ece_up_pct:'Expected Completed Excursion for up-runs only. If up-ECE >> down-ECE, price swings further in the up direction.',hour_ece_down_pct:'Expected Completed Excursion for down-runs only. Asymmetry between up and down ECE reveals directional bias in swing magnitude.',prev_hour_ece:'Previous hour ECE. Leadable. What was the average swing size last hour? Strong persistence in ECE suggests similar this hour.',prev_hour_cwe:'Previous hour CWE. Leadable. Were there outsized swings last hour?',prev_hour_cep_median:'Previous hour median excursion. Leadable. Typical swing size last hour.',prev_hour_cep_tail_ratio:'Previous hour tail ratio. Leadable. Were excursions fat-tailed last hour?',prev_hour_oscillation_ece_ratio:'Oscillation score divided by ECE. Combines quality and magnitude.',hour_trend_r2:'R-squared of linear regression through all tick prices in the hour. High R2 (near 1) = clean linear trend (bad for oscillation trading). Low R2 (near 0) = noisy, choppy price action (good for oscillation trading). Complementary to Hurst: R2 captures short-range linearity.',hour_return_entropy:'Shannon entropy of return directions (up/down/flat), normalized 0-1. High entropy = random, unpredictable moves. Low entropy = patterned or directional. Maximum entropy (1.0) means perfectly random.',hour_order_flow_imbalance:'Volume-weighted net direction (-1 to +1). OFI = sum(size * sign(move)) / sum(size). Unlike up/down ratio, this weights by trade SIZE. A single 10,000 share institutional trade dominates over 100 fractional trades. Near 0 = balanced (ideal for oscillation trading).',hour_vwap_deviation:'(Close - VWAP) / VWAP * 100. How far price has deviated from the volume-weighted average. Extreme deviation = mean-reversion pressure back toward VWAP.',hour_price_level_concentration:'Unique price levels traded / total possible levels in the range. High (near 1) = price touched most levels in the range (distributed). Low = concentrated at few levels, leaving gaps. Low concentration may indicate support/resistance zones.',prev_hour_trend_r2:'Previous hour R2. Leadable. Was last hour trending cleanly or choppy?',prev_hour_entropy:'Previous hour return entropy. Leadable. Was last hour random or patterned?',prev_hour_ofi:'Previous hour order flow imbalance. Leadable. Was institutional flow balanced?',prev_hour_vwap_dev:'Previous hour VWAP deviation. Leadable. Was price stretched from VWAP?'};
